head.script:
			scwin.saveYn = "N";     //팝업으로 띄워졌을때 parent에 보내는 값
			scwin.isPopup = false;  // 팝업인 경우
			scwin._PopupArgs = null; 

			scwin.onpageload = function() {
				// 조회조건 초기화
				scwin.btn_fieldClear_onclick();

				// [AS-IS]에서 해당 페이지를 팝업으로 호출하는 경우가 없어서 주석처리 (26.03.11)
